                    RemoveOps = [RegOp.DeleteValue(RevocationKey, "MaxOCSPResponseAge")],
                    DetectOps = [RegOp.CheckDword(RevocationKey, "MaxOCSPResponseAge", 86400)],
                },
            ];
    }

