    // ── ApplicationGuardPersistencePolicy ──
    private static class _ApplicationGuardPersistencePolicy
    {
        private const string WdagKey = @"HKEY_LOCAL_MACHINE\SOFTWARE\Policies\Microsoft\AppHVSI";

