                    DetectOps = [RegOp.CheckDword(PrivKey, "AuditOtherPrivilegeUseEvents", 3)],
                },
                new TweakDef
                {
                    Id = "privaudit-audit-file-system-failures",
                    Label = "Privilege Audit: Enable File System Access Failure Auditing for ACL Bypass Detection",
